using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class GreetingTools
{
    [McpServerTool, Description("Greets a user by name.")]
    public static string Greet(
        [Description("The name of the person to greet")] string name) =>
        $"Hello, {name}! Welcome to the MCP server.";
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/settings",
        Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns current application configuration.")]
    public static string GetAppSettings() =>
        JsonSerializer.Serialize(new
        {
            Version = "1.0.0",
            Environment = "Production",
            Features = new { DarkMode = true, Notifications = true }
        }, new JsonSerializerOptions { WriteIndented = true });
}

